//! `silan-viking-entities` —— L2.5 the sea-orm Entity layer.
//!
//! # Truth source
//!
//! The [`generated`] module is reverse-generated by `sea-orm-cli` from the Go
//! ent SQLite schema after M0.5a (milestone M4). It is `@generated` code and
//! **must not be hand-edited** — the table/column truth source is the Go ent
//! schema, not this crate (`docs/silan-viking/11` §11 truth-source discipline:
//! hand-written Rust entities drift). To refresh it:
//!
//! ```text
//! cd backend && go run ./cmd/migrate -db-driver sqlite3 \
//!     -db-source "/tmp/silan-schema.db?_fk=1"
//! cd engine && sea-orm-cli generate entity -u "sqlite:///tmp/silan-schema.db" \
//!     -o crates/silan-viking-entities/src/generated --with-serde both
//! ```
//!
//! The L3 `silan-viking-app` `Mapper` still produces the generic
//! `RowSet` / `Row` of `sync::rows`; the typed Entities here slot in behind
//! that same contract. No async runtime or DB driver is enabled — the
//! `SqliteSink` writes via `rusqlite`, not sea-orm.
//!
//! # The endpoint read matrix
//!
//! [`ENDPOINT_READ_MATRIX`] is the M4 exit artifact required by milestone
//! `04` (M4 row) / `10` §10.8.1: the real `endpoint ↔ table ↔ field` map the
//! Go API reads, checked against `backend/internal` and the generated
//! Entities. M8/M9 build the L4 adapters against it. Every table it names is
//! asserted to exist as a generated Entity by the crate tests, so the matrix
//! cannot silently drift away from the schema.

pub mod generated;

/// Re-export the generated entity modules at the crate root so downstream
/// crates can write `silan_viking_entities::content_relation` rather than
/// `silan_viking_entities::generated::content_relation`.
pub use generated::*;

/// `content/SCHEMA.md`'s `version:` value. The reverse-generated Entities
/// must match the schema this constant pins.
pub const SCHEMA_VERSION: u32 = 1;

/// One row of the M4 endpoint read matrix: a Go API endpoint and the SQL
/// tables / public fields it reads. `tables` names must match generated
/// Entity table names (enforced by [`tests::endpoint_matrix_tables_exist`]).
#[derive(Debug, Clone, Copy, PartialEq, Eq, serde::Serialize)]
pub struct EndpointRead {
    /// go-zero endpoint path.
    pub endpoint: &'static str,
    /// SQL tables the handler / logic reads.
    pub tables: &'static [&'static str],
    /// Public fields the frontend contract expects in the response.
    pub fields: &'static [&'static str],
}

/// The M4 exit artifact: the real `endpoint ↔ table ↔ field` read matrix
