/// Look up the read matrix row for an endpoint path.
pub fn endpoint_read(endpoint: &str) -> Option<EndpointRead> {
    ENDPOINT_READ_MATRIX
        .into_iter()
        .find(|e| e.endpoint == endpoint)
}

/// The authoritative column set of a generated table — the schema truth the
/// `SqliteSink` validates `Mapper` output against (`docs/silan-viking/11`
/// truth-source discipline). `None` if `table` is not a generated Entity.
///
/// This is what makes the Entity layer an *enforced* schema source rather
/// than dead code: `sink` builds tables from this set and rejects any
/// `Mapper` row carrying a column the Entity does not declare — so a drift
/// like `content_relation.from_uri` is caught at sync time, not in prod.
pub fn table_columns(table: &str) -> Option<Vec<String>> {
    use sea_orm::{IdenStatic, Iterable};

    /// Collect `<E>::Column`'s names if `<E>` maps to `table`, else `None`.
    fn columns_of<E: sea_orm::EntityTrait>(entity: E, table: &str) -> Option<Vec<String>> {
        if entity.table_name() != table {
            return None;
        }
        Some(
            <E::Column as Iterable>::iter()
                .map(|c| IdenStatic::as_str(&c).to_owned())
                .collect(),
        )
    }

    // One arm per generated Entity — kept aligned with the table list in
    // `generated_table_names()` (tests).
    macro_rules! try_tables {
        ($($m:ident),* $(,)?) => {
            $( if let Some(cols) = columns_of(crate::$m::Entity, table) {
                return Some(cols);
            } )*
        };
    }
    try_tables!(
        blog_posts,
        blog_post_translations,
        projects,
        project_translations,
        project_details,
        ideas,
        idea_translations,
        idea_details,
        personal_info,
        personal_info_translations,
        item_part,
        item_part_translation,
        part_entry,
        part_entry_translation,
        recent_updates,
        recent_update_translations,
        episodes,
        episode_translations,
        episode_series,
        episode_series_translations,
        content_relation,
        content_interaction,
        comments,
        request_logs,
        social_links,
    );
    None
}

#[cfg(test)]
mod tests {
    use super::*;
    use sea_orm::EntityName;
    use std::collections::HashSet;

    /// Compile-time proof that every M0.5a new/changed table reverse-generated
    /// into an Entity module — the M4 acceptance check (`04` M4 row,
    /// `11` §11.1: all new/changed tables must generate successfully).
    #[test]
    fn m0_5a_tables_are_generated() {
        fn assert_entity<E: sea_orm::EntityTrait>() {}
        assert_entity::<crate::content_relation::Entity>();
        assert_entity::<crate::content_interaction::Entity>();
        assert_entity::<crate::annotation::Entity>();
        assert_entity::<crate::item_part::Entity>();
        assert_entity::<crate::item_part_translation::Entity>();
        assert_entity::<crate::part_entry::Entity>();
        assert_entity::<crate::part_entry_translation::Entity>();
        assert_entity::<crate::episodes::Entity>();
        assert_entity::<crate::episode_series::Entity>();
        assert_entity::<crate::episode_translations::Entity>();
        assert_entity::<crate::episode_series_translations::Entity>();
        assert_entity::<crate::request_logs::Entity>();
    }

    /// The set of generated table names — the truth the matrix is checked
    /// against. Listed explicitly because sea-orm has no table-name registry.
    fn generated_table_names() -> HashSet<String> {
        let mut s = HashSet::new();
        macro_rules! add {
            ($($m:ident),* $(,)?) => { $( s.insert(crate::$m::Entity.table_name().to_owned()); )* };
        }
        add!(
            blog_posts,
            blog_post_translations,
            projects,
            project_translations,
            project_details,
            ideas,
            idea_translations,
            idea_details,
            personal_info,
            personal_info_translations,
            item_part,
            item_part_translation,
            part_entry,
            part_entry_translation,
            recent_updates,
            recent_update_translations,
            episodes,
            episode_translations,
            episode_series,
            episode_series_translations,
            content_relation,
            content_interaction,
            comments,
        );
        s
    }

    /// Every table named by the read matrix must exist as a generated Entity —
    /// this is what stops the M4 exit artifact from drifting off the schema.
    #[test]
    fn endpoint_matrix_tables_exist() {
        let known = generated_table_names();
        for endpoint in ENDPOINT_READ_MATRIX {
            for table in endpoint.tables {
                assert!(
                    known.contains(*table),
                    "{} references unknown table {table}",
                    endpoint.endpoint
                );
            }
        }
    }

    #[test]
    fn endpoint_read_finds_by_path() {
        assert!(endpoint_read("GET /api/v1/resume").is_some());
        assert!(endpoint_read("GET /api/v1/nonexistent").is_none());
    }
}
